bile Access</div></div><div><div class="icon">🏆</div><div class="txt">Certificate</div></div></div><button class="cta" onclick="window.open(\"{{offer_url||#}}\",\"_blank\")">{{cta_text||ENROLL NOW — $97}}</button><p class="note">{{note||30-day money-back guarantee}}</p></div></body></html>',
  '[{"key":"headline","label":"Headline","type":"text","default":"Learn to"},{"key":"headline2","label":"Highlight","type":"text","default":"Trade Profitably"},{"key":"description","label":"Description","type":"textarea","default":"The exact strategy used by 6-figure traders. Step-by-step video course with live mentorship."},{"key":"badge","label":"Badge","type":"text","default":"📈 ENROLLMENT OPEN"},{"key":"cta_text","label":"Button Text","type":"text","default":"ENROLL NOW — $97"},{"key":"offer_url","label":"Offer URL","type":"text","required":true},{"key":"bg_color","label":"Background","type":"color","default":"#090a0f"},{"key":"accent_color","label":"Accent","type":"color","default":"#10b981"},{"key":"note","label":"Note","type":"text","default":"30-day money-back guarantee"}]',
